insert into public.problems
  (id, title, question, answer, explanation, answer_keywords, category, difficulty)
values
('10000000-0000-4000-8000-000000000001', '사라진 발자국', '눈 덮인 공원 한가운데에 신발 한 켤레만 놓여 있었다. 주변에는 다가오거나 떠난 발자국이 전혀 없었다. 어떻게 된 일일까?', '신발은 눈이 내리기 전에 놓였고, 이후 내린 눈이 이전 발자국을 모두 덮었다.', '사람이 사라진 것이 아니라 시간의 순서가 착시를 만들었다. 신발과 발자국이 먼저 있었고 새 눈이 흔적만 지웠다.', array['눈', '발자국', '덮였다', '먼저'], 'Logic', 'Easy'),
('10000000-0000-4000-8000-000000000002', '한 모금의 물', '한 여자가 카페에서 물을 주문했다. 직원은 갑자기 큰 소리를 냈고, 여자는 고맙다고 말한 뒤 물을 마시지 않고 떠났다. 왜 그랬을까?', '여자는 딸꾹질을 멈추려고 물을 주문했고, 직원이 놀라게 해 딸꾹질이 멈췄다.', '직원의 행동은 위협이 아니라 손님의 목적을 알아챈 즉석 처방이었다.', array['딸꾹질', '놀라게', '멈췄다'], 'Paradox', 'Easy'),
('10000000-0000-4000-8000-000000000003', '마지막 엘리베이터', '한 남자는 매일 20층 집으로 돌아오지만 맑은 날에는 12층에서 내려 계단을 오른다. 비 오는 날에는 곧장 20층까지 간다. 왜일까?', '키가 작은 남자는 평소 12층 버튼까지만 손이 닿지만 비 오는 날에는 우산으로 20층 버튼을 누른다.', '날씨가 엘리베이터를 바꾸는 것이 아니라 남자가 가진 도구를 바꾼다.', array['키', '작다', '우산', '버튼'], 'Logic', 'Easy'),
('10000000-0000-4000-8000-000000000004', '잠긴 스튜디오', '안에서 잠긴 녹음실에서 음악가가 쓰러진 채 발견되었다. 창문은 닫혀 있었고 다른 사람은 들어오지 않았다. 바닥에는 물만 조금 남아 있었다. 무슨 일이 있었을까?', '음악가는 큰 얼음 조각 위에 올라 높은 장비를 조정하다가 얼음이 녹으며 균형을 잃고 넘어졌다.', '사라진 발판이 밀실의 빈 공간과 바닥의 물을 함께 설명한다.', array['얼음', '녹다', '발판', '넘어졌다'], 'Mystery', 'Medium'),
('10000000-0000-4000-8000-000000000005', '꺼진 등대', '등대지기는 어느 날 밤 불을 끄고 잠들었다. 다음 날 그는 신문을 읽고 자신이 큰 사고를 일으켰다는 사실을 알았다. 무슨 일이 있었을까?', '등대 불이 꺼져 배가 암초를 피하지 못하고 사고가 났다.', '평범한 소등 행동이 항해자에게는 안전 신호의 상실이었다.', array['등대', '배', '암초', '불'], 'Mystery', 'Medium'),
('10000000-0000-4000-8000-000000000006', '두 개의 시계', '정확히 같은 시각에 맞춘 두 시계가 같은 방에 있었지만 하루 뒤 서로 다른 시간을 가리켰다. 둘 다 고장 나지 않았다. 왜일까?', '하나는 12시간제 시계이고 다른 하나는 24시간제 시계였으며 표시 방식이 달랐다.', '같은 시간을 다른 체계로 표시해 숫자만 보면 달라 보였다.', array['12시간', '24시간', '표시', '방식'], 'Logic', 'Easy'),
('10000000-0000-4000-8000-000000000007', '빈 우편함', '한 사람은 매일 빈 우편함을 확인하고도 만족스러운 표정으로 집에 들어갔다. 그는 편지를 기다리던 중이었다. 왜 기뻐했을까?', '그는 협박 편지가 더 오지 않기를 바라고 있었고, 빈 우편함은 안전하다는 뜻이었다.', '기다린다는 말이 도착을 기대한다는 뜻은 아니다. 그는 나쁜 소식의 부재를 확인했다.', array['협박', '오지 않다', '안전', '빈'], 'Weird', 'Medium'),
('10000000-0000-4000-8000-000000000008', '쌓여 있는 우유병', '매일 아침 이웃집 현관 앞을 지나던 남자는 우유병 세 개가 그대로 쌓여 있는 것을 보고 즉시 관리실에 연락했다. 왜 그랬을까?', '혼자 사는 이웃은 매일 배달된 우유를 아침마다 바로 가져갔다. 사흘치가 쌓였다는 것은 이웃이 며칠 동안 현관에 나오지 못할 문제가 생겼다는 신호였다.', '평소 반복되던 일상이 멈춘 것이 이상 징후였다. 남자는 이웃의 생활 습관을 알고 있었기 때문에 도움을 요청했다.', array['매일', '혼자 산다', '가져간다', '사흘', '도움'], 'Logic', 'Easy'),
('10000000-0000-4000-8000-000000000009', '짧아진 여행', '기차 여행을 마친 남자는 목적지에 예상보다 일찍 도착했지만 기뻐하지 않았다. 기차는 지연도 과속도 하지 않았다. 왜일까?', '그는 시차가 있는 지역으로 이동했고 시계상 도착 시간이 빨라 보였을 뿐 실제 여행 시간은 같았다.', '운행 시간이 아니라 출발지와 도착지의 시간대가 달랐다.', array['시차', '시간대', '시계', '여행 시간'], 'Logic', 'Medium'),
('10000000-0000-4000-8000-000000000010', '흐려진 창문', '겨울 동안 비어 있어야 하는 산장을 살피던 관리인은 창문 한 장이 안쪽에서 뿌옇게 흐려진 것을 보고 구조대에 연락했다. 왜 그랬을까?', '난방이 꺼진 빈 산장의 창문은 안쪽에서 흐려질 이유가 없다. 한 장에 생긴 김은 누군가 가까이에서 숨을 쉬며 내뿜은 따뜻하고 습한 공기가 차가운 유리에 닿았다는 흔적이었다.', '관리인은 산장 안에 사람이 있으며 밖으로 도움을 요청하지 못하는 상황일 수 있다고 판단했다.', array['겨울', '빈 산장', '김', '숨', '사람'], 'Mystery', 'Medium'),
('10000000-0000-4000-8000-000000000011', '바다 거북 스프', E'한 남자가 바닷가에 있는 고급 레스토랑에 들어가 바다거북 수프를 주문했다.\n\n바다거북 수프를 한 숟갈 떠먹은 그는 주방장을 불러 물었다.\n"이거 정말로 바다거북 수프인가요?"\n"네, 틀림없는 바다거북 수프가 맞습니다."\n\n남자는 계산을 마친 뒤 집에 돌아가서 자살했다. 왜 그랬을까?', '남자는 과거 비행기 추락으로 무인도에 조난당했다. 식량이 떨어지자 다른 조난자들은 죽은 사람의 고기를 그에게 바다거북 수프라고 속여 먹였다. 구조된 뒤 진짜 바다거북 수프를 먹어 본 남자는 과거에 먹은 것이 사람 고기였음을 깨닫고 충격을 받아 자살했다.', '레스토랑의 수프 맛이 과거 조난 중 먹었던 수프와 전혀 달랐기 때문에, 남자는 동료들이 자신을 살리려고 사람 고기를 바다거북 고기라고 속였다는 진실을 깨달았다.', array['비행기 추락', '무인도', '조난', '사람 고기', '속였다', '맛이 다르다'], 'Mystery', 'Hard'),
('10000000-0000-4000-8000-000000000012', '생일', E'A, B, C는 오랜 친구 사이입니다.\nA의 생일날, A는 B와 C를 집에 초대했습니다.\nA의 집에 도착한 B와 C는 생일 축하 노래를 부르고 박수를 치며 진심으로 A의 생일을 축하해 주었습니다.\n그런데 A는 분노했고 B와 C를 살해했습니다. 왜 그랬을까요?', 'A는 시각장애인이다. 과거 세 사람은 함께 조난당해 굶어 죽을 위기에 처했고, 각자 한쪽 팔을 잘라 먹기로 했다. 그러나 B와 C는 자신들도 팔을 잘랐다고 A를 속이고 실제로는 A의 팔만 먹었다. 생일날 B와 C가 박수 치는 소리를 들은 A는 두 사람의 양팔이 멀쩡하다는 사실을 깨닫고, 속았다는 분노로 둘을 살해했다.', '박수 소리는 시각장애인인 A에게 B와 C가 두 손을 모두 가지고 있다는 증거였다. 그 순간 과거 조난 당시 자신만 팔을 잃었다는 사실을 알게 되었다.', array['시각장애인', '조난', '팔', '박수', '속였다', '두 손'], 'Mystery', 'Hard'),
('10000000-0000-4000-8000-000000000013', '횡단보도', '빨간불인 횡단보도 앞에서 어느 남자가 갑자기 건너기 시작하여 차에 치였습니다. 왜 그랬을까요?', '남자는 스마트폰을 보며 신호를 기다리고 있었다. 옆 사람이 바닥의 개미를 밟으려고 한 발을 앞으로 내딛자, 남자는 신호가 바뀌어 사람들이 출발한 것으로 착각하고 따라 움직였다. 하지만 신호는 여전히 빨간불이어서 지나가던 차에 치였다.', '남자는 신호등을 직접 확인하지 않고 옆 사람의 움직임을 보행 시작 신호로 오해했다. 옆 사람은 횡단보도를 건너려던 것이 아니라 개미를 밟으려던 것이었다.', array['스마트폰', '개미', '옆 사람', '착각', '빨간불', '따라 움직였다'], 'Logic', 'Medium'),
('10000000-0000-4000-8000-000000000014', '철수의 부모님', E'철수의 부모님은 TV에 나와 연일 대중의 입방아에 오르내리고 있었습니다.\n영희는 이런 철수의 부모님을 보고 철수에게 "너희 부모님이 또 뉴스에 나오고 있어!"라고 말했습니다.\n이 말을 들은 철수는 더 슬퍼졌습니다. 무슨 일이 생긴 걸까요?', '영희가 철수를 납치해 감금하고 있었다. 철수의 부모님은 실종된 철수를 찾기 위해 계속 뉴스에 출연하고 있었고, 영희는 그 모습을 철수에게 보여 주며 조롱했다.', '부모님이 뉴스에 나온 이유는 철수의 실종 사건 때문이었다. 납치범인 영희는 부모님의 호소를 철수에게 일부러 알려 주어 고통을 주었다.', array['납치', '감금', '실종', '부모님', '뉴스', '조롱'], 'Mystery', 'Medium')
